  ('judicial-de09bf8b-moex-00149', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲於檳榔攤趁顧店小姐乙在後面收取包裹，無法看顧櫃檯時，將置於抽屜內之現金2,000元取走， 甲之刑事責任為何？', '["搶奪罪", "竊盜罪", "強制罪", "詐欺取財罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00150', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '甲與乙係兄弟，已成年分家未同住。甲因缺錢花用，未經乙同意，即將乙先前借給甲暫時使用之 機車1台，賣給中古機車行，得款新臺幣5,000元後，自行花用完畢。下列敘述何者正確？', '["甲構成竊盜罪", "甲所為犯罪因其與乙係兄弟，得免除其刑", "甲所為犯罪因其與乙係兄弟，須告訴乃論", "甲不構成犯罪，只需賠償乙新臺幣5,000元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00151', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-e2754278', 'sub-judicial-de09bf8b-01', NULL, 'single_choice', '下列何者不是刑法第356條損害債權罪之構成要件？', '["債務人於將受強制執行之際", "債務人於強制執行後", "意圖損害債權人之債權", "毀壞、處分或隱匿其財產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00152', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-2909f946', 'sub-judicial-de09bf8b-02', NULL, 'essay', '甲列乙為被告，訴請乙給付甲新臺幣（以下同）100萬元。甲主張乙於五
年前向甲借款100萬元，約定返還期間為五年而乙逾期未還。對此，乙主
張兩造原為好友，乙與甲協商後甲已同意「乙得延期半年清償」之請求。
對此合意延期清償之事實，甲於準備程序中未為否認，亦未為明確之陳
述。於歷經數次準備程序期日與言詞辯論期日後，甲於第一審之程序後階
段（準備程序終結後）復爭執此合意延期清償之事實，並主張僅同意乙延
期半個月清償。試問：如何評價甲之相關程序行為之效力？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "5946a93f82a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00153', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-2909f946', 'sub-judicial-de09bf8b-02', NULL, 'essay', '甲列乙為被告，向管轄法院起訴，先位聲明請求撤銷兩造之婚姻，後位
聲明請求判決兩造離婚。甲起訴主張之事實與依據略為：「兩造結婚時，
乙故意隱瞞其有重大精神病之事實致甲受詐欺而允婚，甲擬先依民法第
997 條之規定撤銷婚姻；若先位之訴無理由，則以乙之精神病已重大影
響婚後兩造之生活，一年來已無共同生活之事實，而於後位聲明請求判
准離婚。」第一審法院認為甲先位之訴為無理由，而後位之訴為有理由，
判決兩造離婚，並駁回甲先位之訴。試附理由說明：
若甲對先位之訴提起上訴，乙未提起上訴，而第二審法院認為甲先位
之訴為有理由時，應如何判決？（13分）
若第一審之判決書於民國（以下同）112 年 7月 3 日合法送達予兩造，
甲於同年 7月 20日提起上訴，復又於同年 7月 26日撤回上訴，乙則
未提起上訴。試問：本件之判決何時確定？（12分）
20460', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "5946a93f82a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00154', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-2909f946', 'sub-judicial-de09bf8b-02', NULL, 'essay', '被告甲涉犯貪污罪嫌（屬強制辯護案件），被檢察官依法聲請羈押，經辯
護人與檢察官進行攻防程序，法官訊問後，認有羈押原因及必要性，裁
定羈押。嗣後被告之辯護人具保，向法院聲請停止羈押，法院依法審查
後，認為雖有羈押之原因但無羈押之必要，許可具保而停止羈押並命被
告甲定期向檢察官報到。惟被告甲無正當理由未定期向檢察官報到，檢
察官向法院聲請撤銷「原停止羈押之裁定」，再執行羈押，法官行再執行
羈押審查庭時，僅被告及檢察官到庭進行攻防程序，法官訊問後，認有
再執行羈押理由及必要性，裁定再執行羈押。試論法院行「再執行羈押」
之程序是否合法？理由安在？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "5946a93f82a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00155', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-2909f946', 'sub-judicial-de09bf8b-02', NULL, 'essay', '檢察官以甲涉犯刑法第 320條普通竊盜罪嫌提起公訴，審判期日時，到
庭實行公訴檢察官更正法條為刑法第 321 條第 1項第 1款「侵入住宅竊
盜罪」，法院審理結果，認為起訴書記載之犯罪事實，與審理結果認定之
犯罪事實之間，具有同一性，對甲為刑法第 321條第 1 項 1款有罪判決，
然未在判決理由書引用刑事訴訟法第 300 條。試論法院之判決是否合
法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "5946a93f82a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0407", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00156', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'essay', '甲將其對乙之消費借貸債權以新臺幣（下同）200 萬元出賣給丙，然甲
對乙之消費借貸債權，經法院判決確定不存在。試問：甲、丙間之債權
買賣契約效力如何？丙就已支付價金以及其利息之損害，應如何向甲請
求賠償？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00157', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'essay', '甲擅自在登記為乙所有之A土地上興建違章房屋B以供居住，為乙所不
知。嗣後，乙將A地設定抵押權於丙，作為向丙借款之擔保。借款期滿，
乙未清償債務，丙向管轄法院聲請拍賣抵押物。試問：甲對 B 屋有何權
利？丙向法院聲請連同土地上之B屋併付拍賣，是否有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL),
  ('judicial-de09bf8b-moex-00158', 'judicial-de09bf8b', 'judicial-de09bf8b-moex-112-a7c7609b', 'sub-judicial-de09bf8b-03', NULL, 'single_choice', '關於意思表示之解釋、單獨虛偽意思表示與通謀虛偽意思表示，下列敘述何者錯誤？', '["如以與交易慣行不同之意思為解釋時，限於對話人知其情事或可得而知，否則仍不能逸出交易 慣行之意義", "表意人縱有表示，但內心之真實意思，若為相對人所明知者，則認為應以其內心真實意思為主， 其表達於外部之意思表示，違反內心意思，不應使其發生效力", "單獨虛偽意思表示，僅適用於法律行為", "關於通謀虛偽意思表示之善意第三人，係指對於新取得之財產上權利，因虛偽之意思表示而必 受變動之人，包含雙方當事人之債權人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:19+00:00", "source_pdf_sha1": "2b56069a4816", "answer_pdf_sha1": "083e695c71f6", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法院書記官"}'::jsonb, NULL)
